use std::collections::HashMap;

#[derive(Debug)]
struct Todo {
    id: u32,
    title: String,
    completed: bool,
}

struct TodoList {
    todos: Vec<Todo>,
    next_id: u32,
}

impl TodoList {
    fn new() -> Self {
        TodoList {
            todos: Vec::new(),
            next_id: 1,
        }
    }

    fn add(&mut self, title: String) {
        let todo = Todo {
            id: self.next_id,
            title,
            completed: false,
        };
        self.next_id += 1;
        println!("Added: #{} - {}", todo.id, todo.title);
        self.todos.push(todo);
    }

    fn remove(&mut self, id: u32) -> bool {
        if let Some(pos) = self.todos.iter().position(|t| t.id == id) {
            let removed = self.todos.remove(pos);
            println!("Removed: #{} - {}", removed.id, removed.title);
            true
        } else {
            println!("Todo #{} not found", id);
            false
        }
    }

    fn complete(&mut self, id: u32) -> bool {
        if let Some(todo) = self.todos.iter_mut().find(|t| t.id == id) {
            todo.completed = true;
            println!("Completed: #{} - {}", todo.id, todo.title);
            true
        } else {
            println!("Todo #{} not found", id);
            false
        }
    }

    fn list(&self) {
        if self.todos.is_empty() {
            println!("No todos!");
            return;
        }
        println!("\n--- Todo List ---");
        for todo in &self.todos {
            let status = if todo.completed { "[x]" } else { "[ ]" };
            println!("  {} #{}: {}", status, todo.id, todo.title);
        }
        println!();
    }
}

fn main() {
    let mut todos = TodoList::new();
    todos.add("Learn Rust ownership".to_string());
    todos.add("Build a CLI app".to_string());
    todos.list();
    todos.complete(1);
    todos.list();
    todos.remove(2);
    todos.list();
}
